parameters.jsCode:
// Obtener el nombre del producto desde el AI Agent
const nombreProducto = $fromAI('product_name', 'Nombre del producto a buscar (ej: hamburguesa pozu, patatas trufadas)', 'string');

// Obtener el catálogo de productos del nodo anterior
const productos = $('Consultar Catálogo Productos').all();

if (!productos || productos.length === 0) {
  return 'Error: No se pudo cargar el catálogo de productos.';
}

// Buscar el producto por nombre (búsqueda flexible)
const nombreBuscado = nombreProducto.toLowerCase().trim();
const productoEncontrado = productos.find(item => {
  const nombreProducto = item.json.name?.toLowerCase() || '';
  return nombreProducto.includes(nombreBuscado) || nombreBuscado.includes(nombreProducto);
});

if (!productoEncontrado) {
  return `Producto "${nombreProducto}" no encontrado en el catálogo. Solicita confirmación manual al cliente.`;
}

const producto = productoEncontrado.json;

// Verificar disponibilidad
if (producto.is_available === false) {
  return `El producto "${producto.name}" NO está disponible actualmente. Ofrece alternativas al cliente.`;
}

// Construir respuesta estructurada
const respuesta = {
  nombre: producto.name || 'Sin nombre',
  precio: producto.price || 0,
  ingredientes: producto.ingredients || 'No especificados',
  alergenos: producto.allergens || 'Sin alérgenos declarados',
  disponible: true,
  categoria: producto.category || 'Sin categoría',
  descripcion: producto.description || ''
};

return `PRODUCTO VERIFICADO:
- Nombre: ${respuesta.nombre}
- Precio: ${respuesta.precio}€
- Ingredientes: ${respuesta.ingredientes}
- Alérgenos: ${respuesta.alergenos}
- Disponible: Sí
- Categoría: ${respuesta.categoria}

USA ESTE PRECIO EXACTO (${respuesta.precio}€) para calcular el total del pedido.`;

